/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const results = [];

    for (const [l, r, k] of queries) {
        // 1. Identify all unique even numbers in nums[l..r]
        const removedEvensSet = new Set();
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            if (num % 2 === 0) {
                removedEvensSet.add(num);
            }
        }
        const removedEvens = Array.from(removedEvensSet);

        // 2. Determine the target number we are looking for.
        // We are looking for the k-th smallest positive even number *not* in removedEvens.
        // The sequence of all positive even numbers is 2, 4, 6, 8, 10, ...
        // The j-th positive even number is 2 * j.

        // Let N be the target even number we are looking for, N = 2 * J.
        // The count of positive even numbers less than or equal to N is J.
        // The count of removed even numbers less than or equal to N is |{x in removedEvens | x <= N}|.
        // The count of remaining positive even numbers less than or equal to N is J - |{x in removedEvens | x <= N}|.

        // We want this count to be at least k.
        // J - |{x in removedEvens | x <= 2J}| >= k

        // This suggests we can use Binary Search on the answer (J, or N=2J).

        // Since k is up to 10^9, and we are looking for the k-th number,
        // the answer N could be around 2 * 10^9 (if no numbers were removed).
        // A safe upper bound for N is 2 * 10^14 if all numbers up to 10^9 were removed, 
        // but since k <= 10^9, the answer N will be around 2 * 10^9 + (number of removed evens).
        // Max number of removed evens is N.length <= 10^5.
        // So, N is roughly <= 2 * 10^9 + 10^5. A safe upper bound for J is 10^9 + 10^5.

        let low = 1; // Corresponds to N=2
        // A safe upper bound for J: k + |removedEvens|. Since k <= 10^9 and |removedEvens| <= 10^5
        let high = k + removedEvens.length + 2; 
        let ans_J = high; // Store the smallest J such that the count is >= k

        while (low <= high) {
            const J = Math.floor((low + high) / 2);
            const N = 2 * J;

            // Count how many removed evens are <= N
            let removedCount = 0;
            for (const removed of removedEvens) {
                if (removed <= N) {
                    removedCount++;
                }
            }

            // Count of remaining evens <= N
            const remainingCount = J - removedCount;

            if (remainingCount >= k) {
                // N might be the answer, try smaller J
                ans_J = J;
                high = J - 1;
            } else {
                // Need a larger N (larger J)
                low = J + 1;
            }
        }

        const result_N = 2 * ans_J;
        results.push(result_N);
    }

    return results;
}

